var largestSquareArea = function(bottomLeft, topRight) {
    const n = bottomLeft.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const ix1 = Math.max(bottomLeft[i][0], bottomLeft[j][0]);
            const iy1 = Math.max(bottomLeft[i][1], bottomLeft[j][1]);
            const ix2 = Math.min(topRight[i][0], topRight[j][0]);
            const iy2 = Math.min(topRight[i][1], topRight[j][1]);
            if (ix2 > ix1 && iy2 > iy1) {
                const side = Math.min(ix2 - ix1, iy2 - iy1);
                best = Math.max(best, side * side);
            }
        }
    }
    return best;
};
